using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// Source-gen context that only knows about Person (not Order).
var options = new JsonSerializerOptions { TypeInfoResolver = AppContext.Default };

// ── 1. Strongly-typed retrieval ──────────────────────────────────
// GetTypeInfo<T>() returns JsonTypeInfo<T> directly — no cast needed.
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Typed info for : {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Alice", 30), personInfo);
Console.WriteLine($"Serialized     : {json}");

Person? p = JsonSerializer.Deserialize(json, personInfo);
Console.WriteLine($"Round-tripped   : {p}");

// ── 2. Probe without throwing ────────────────────────────────────
// TryGetTypeInfo returns false instead of throwing when metadata is absent.
if (options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? found))
    Console.WriteLine($"\nPerson metadata found   : {found!.Type.Name}");

if (!options.TryGetTypeInfo(typeof(Order), out _))
    Console.WriteLine("Order  metadata NOT found (no exception thrown)");

// Records used in the demo
public record Person(string Name, int Age);
public record Order(int Id);

